async def check_for_drift(
    messages: list[dict],
    system: str,
    check_interval: int = 10,
) -> str | None:
    if len(messages) < check_interval * 2:
        return None

    # Only check every N turns
    turn_count = sum(1 for m in messages if m["role"] == "user")
    if turn_count % check_interval != 0:
        return None

    check_response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=system,
        messages=messages + [
            {
                "role": "user",
                "content": (
                    "In one or two sentences, summarise your current understanding "
                    "of what the user is trying to accomplish."
                ),
            }
        ],
    )
    return check_response.content[0].text

from pydantic import BaseModel

class ConversationEntities(BaseModel):
    account_ids: list[str] = []
    product_names: list[str] = []
    error_codes: list[str] = []
    open_issues: list[str] = []

EXTRACT_ENTITIES_TOOL = {
    "name": "extract_entities",
    "description": "Extract key entities from the conversation for context caching.",
    "input_schema": {
        "type": "object",
        "properties": {
            "account_ids": {"type": "array", "items": {"type": "string"}},
            "product_names": {"type": "array", "items": {"type": "string"}},
            "error_codes": {"type": "array", "items": {"type": "string"}},
            "open_issues": {"type": "array", "items": {"type": "string"}},
        },
        "required": ["account_ids", "product_names", "error_codes", "open_issues"],
    },
}

def extract_entities(messages: list[dict]) -> ConversationEntities:
    # Use only the last 10 turns to keep the call cheap
    recent = messages[-20:]
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        tools=[EXTRACT_ENTITIES_TOOL],
        tool_choice={"type": "tool", "name": "extract_entities"},
        messages=recent + [
            {"role": "user", "content": "Extract the key entities from this conversation."}
        ],
    )
    for block in response.content:
        if block.type == "tool_use" and block.name == "extract_entities":
            return ConversationEntities(**block.input)
    return ConversationEntities()
